import React from "react";
import { graphql } from "gatsby";
import { initializeApp } from "firebase/app";
import { getFirestore } from "firebase/firestore/lite";
// import Layout from "@components/layout";
// import BreadCrumb from "@components/common/breadcrumb";
import Seo from "@components/seo";
import NFTDevIndex from "@screens/nft-development";
import { useLocation } from "@reach/router";
import Layout_v2 from "@components/layout_v2";
import BreadCrumbV2 from "@components/common/breadcrumb-v2";

const NFTDevelopmentCompany = (props) => {
  const app = initializeApp(props?.data?.site?.siteMetadata?.firestore);
  const db = getFirestore(app);
  const breadcrumbLinks = [
    { text: "Home", link: "/" },
    { text: "NFT Development Company", link: null },
  ];
  const { data } = props;
  const fileUrl =
    data?.nftDevImg?.childImageSharp?.gatsbyImageData?.images?.fallback?.src;
  const location = useLocation();
  const validData = data?.allMetaJson?.nodes[0];
  const schemaMarkup = {
    "@context": "https://schema.org",
    "@graph": [
      {
        "@type": "Organization",

        name: "Justtry Technologies",
        url: "https://justtrytech.com",
        logo: "https://justtrytech.com/static/company_logo-a8a6f67b23da723440dd6bdb258ac7e8.svg",
        description:
          "An NFT development company makes NFT platforms, smart contracts and marketplaces that are secure and scalable to handle digital assets and collectibles.",
        sameAs: [
          "https://www.linkedin.com/company/justtry-technologies",
          "https://twitter.com/justtrytech",
        ],
        email: "sales@justtrytech.com",
        telephone: "+91 9500139200",
        address: {
          "@type": "PostalAddress",
          streetAddress:
            "179/3, Kamarajar salai, (Near Tamilnadu Chamber of Commerce), Madurai – 625009.",
          addressLocality: "Madurai",
          addressCountry: "IN",
          addressRegion: "Tamilnadu",
          postalCode: "625009",
        },
        aggregateRating: {
          "@type": "AggregateRating",
          ratingValue: "4.8",
          reviewCount: "1237",
        },
      },
      {
        "@type": "FAQPage",

        mainEntity: [
          {
            "@type": "Question",
            name: "What is an NFT company?",
            acceptedAnswer: {
              "@type": "Answer",
              text: "An NFT company is a company that creates, operates or maintains non-fungible token projects, such as NFT creation, smart contracts, marketplaces and platforms dealing with digital assets.",
            },
          },
          {
            "@type": "Question",
            name: "Is NFT legal in India?",
            acceptedAnswer: {
              "@type": "Answer",
              text: "Yes - NFTs in India are legal and are considered to be virtual digital assets, though no explicit regulation applies yet, and therefore, rules are still being developed.",
            },
          },
          {
            "@type": "Question",
            name: "What is an NFT developer?",
            acceptedAnswer: {
              "@type": "Answer",
              text: "A developer of NFTs is a blockchain developer that develops NFT smart contracts, minting systems, and digital asset and collectible marketplaces.",
            },
          },
        ],
      },
    ],
  };

  return (
    <Layout_v2 db={db}>
      <Seo
        title={validData?.title}
        metaTitle={validData?.metaTitle}
        metaKeyword={validData?.metaKeyword}
        description={validData?.description}
        image={fileUrl}
        siteFirestore={data?.site?.siteMetadata?.firestore}
        slug={location.pathname.split("/")?.[1]}
        schemaMarkup={schemaMarkup}
      ></Seo>
      <BreadCrumbV2 items={breadcrumbLinks} />
      <main>
        <NFTDevIndex db={db} />
      </main>
    </Layout_v2>
  );
};

export default NFTDevelopmentCompany;

export const queryData = graphql`
  query MyQuery {
    nftDevImg: file(relativePath: { eq: "nft-development.png" }) {
      childImageSharp {
        gatsbyImageData
      }
    }
    site {
      siteMetadata {
        firestore {
          apiKey
          appId
          authDomain
          messagingSenderId
          projectId
          storageBucket
        }
      }
    }
    allMetaJson(filter: { slug: { eq: "nft-development-company" } }) {
      nodes {
        metaTitle
        metaKeyword
        title
        slug
        description
      }
    }
  }
`;
